/*
 * BTPopover — floating content panel.
 *
 * Used by Vue (BTPopoverContent.vue) and React (BTPopoverContent.tsx).
 * This single CSS file is shared between both framework packages.
 *
 * Figma node 2057-3539 · D - Popover
 *
 * Positioning is handled entirely in JS (position: fixed + inline top/left).
 * The panel starts at opacity: 0 so it is invisible while JS measures it;
 * adding .bt-popover-content--visible triggers the entrance animation.
 */

/* ── Trigger wrapper ──────────────────────────────────────────────── */
/*
 * display: contents makes the span layout-transparent — it does not
 * create its own box and does not affect the trigger element's sizing
 * or flow. Event bubbling still works through it normally.
 */
.bt-popover-trigger {
  display: contents;
}

/* ── Content panel ────────────────────────────────────────────────── */
.bt-popover-content {
  position: fixed;
  z-index: 1000;
  min-width: 200px;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-md);
  padding: var(--space-lg);
  /* Subtle elevation — raw rgba allowed for non-tokenised overlays */
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.08), 0 1px 4px rgba(0, 0, 0, 0.04);
  box-sizing: border-box;
  outline: none;

  /* Hidden until JS positions and reveals the panel */
  opacity: 0;
}

/* Bare mode — strips visual chrome; embedded content provides its own card.
   Use with BTDropdownList, BTDropdownMenu, or any self-styled content. */
.bt-popover-content--bare {
  background: none;
  border: none;
  box-shadow: none;
  padding: 0;
  border-radius: 0;
}

.bt-popover-content--visible {
  animation: bt-popover-in 150ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

@keyframes bt-popover-in {
  from {
    opacity: 0;
    transform: scale(0.96);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

/**
 * BTPopover — root component (React).
 *
 * Manages open/close state and distributes context to
 * BTPopoverTrigger and BTPopoverContent.
 *
 * Supports uncontrolled (internal state) and controlled (open + onOpenChange) modes.
 *
 * @example
 * // Uncontrolled
 * <BTPopover>
 *   <BTPopoverTrigger>
 *     <BTButton label="Open" />
 *   </BTPopoverTrigger>
 *   <BTPopoverContent align="start">
 *     <p>Content</p>
 *   </BTPopoverContent>
 * </BTPopover>
 *
 * @example
 * // Controlled
 * const [open, setOpen] = useState(false);
 * <BTPopover open={open} onOpenChange={setOpen}>
 *   ...
 * </BTPopover>
 */
import { createContext, useContext, useRef, useState, useCallback } from 'react';
import type { BTPopoverProps } from './BTPopover.types';

// ── Internal context ─────────────────────────────────────────────────────────

export interface BTPopoverContextValue {
  isOpen:     boolean;
  triggerRef: React.MutableRefObject<HTMLElement | null>;
  toggle:     () => void;
  close:      () => void;
}

export const BTPopoverContext = createContext<BTPopoverContextValue | null>(null);

export function useBTPopoverContext(): BTPopoverContextValue {
  const ctx = useContext(BTPopoverContext);
  if (!ctx) throw new Error('BTPopoverTrigger / BTPopoverContent must be inside <BTPopover>.');
  return ctx;
}

// ── Component ────────────────────────────────────────────────────────────────

export function BTPopover({ open: controlledOpen, onOpenChange, children }: BTPopoverProps) {
  const [internalOpen, setInternalOpen] = useState(false);
  const isOpen     = controlledOpen ?? internalOpen;
  const triggerRef = useRef<HTMLElement | null>(null);

  const toggle = useCallback(() => {
    const next = !isOpen;
    if (controlledOpen === undefined) setInternalOpen(next);
    onOpenChange?.(next);
  }, [isOpen, controlledOpen, onOpenChange]);

  const close = useCallback(() => {
    if (controlledOpen === undefined) setInternalOpen(false);
    onOpenChange?.(false);
  }, [controlledOpen, onOpenChange]);

  return (
    <BTPopoverContext.Provider value={{ isOpen, triggerRef, toggle, close }}>
      {children}
    </BTPopoverContext.Provider>
  );
}

BTPopover.displayName = 'BTPopover';

/**
 * BTPopover — public prop types (React).
 *
 * Figma node 2057-3539 · D - Popover
 */

export type BTPopoverSide = 'top' | 'bottom' | 'left' | 'right';
export type BTPopoverAlign = 'start' | 'center' | 'end';

export interface BTPopoverProps {
  /** Controlled open state. */
  open?: boolean;
  /** Called when the popover requests a state change. */
  onOpenChange?: (open: boolean) => void;
  children?: React.ReactNode;
}

export interface BTPopoverTriggerProps {
  /**
   * Merge the click handler and ref directly onto the child element
   * instead of wrapping it in a <span>. The child must be a single React
   * element that accepts `ref` and `onClick`.
   */
  asChild?: boolean;
  children?: React.ReactNode;
}

export interface BTPopoverContentProps {
  /** Horizontal alignment of the panel relative to the trigger. Default: 'start'. */
  align?: BTPopoverAlign;
  /** Which side of the trigger to render on. Default: 'bottom'. */
  side?: BTPopoverSide;
  /** Gap in px between trigger edge and panel. Default: 8. */
  sideOffset?: number;
  /**
   * Strips the panel's visual chrome (background, border, shadow, padding,
   * border-radius) so that the embedded content provides its own card styling.
   *
   * Use when composing with components that already have a card look,
   * e.g. `BTDropdownList`, `BTDropdownMenu`.
   *
   * @default false
   * @example
   * ```tsx
   * <BTPopoverContent align="end" side="bottom" bare>
   *   <BTDropdownList items={items} onSelect={onSelect} />
   * </BTPopoverContent>
   * ```
   */
  bare?: boolean;
  /** Extra CSS class(es). */
  className?: string;
  children?: React.ReactNode;
}

/**
 * BTPopoverContent — the floating panel (React).
 *
 * Portal-rendered via createPortal so it escapes overflow:hidden ancestors.
 * Positioned via JS (position: fixed + inline top/left).
 *
 * @example
 * <BTPopoverContent align="start" side="bottom" sideOffset={8}>
 *   <p>Content</p>
 * </BTPopoverContent>
 */
import './BTPopover.css';
import { useEffect, useRef, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { useBTPopoverContext } from './BTPopover';
import type { BTPopoverContentProps } from './BTPopover.types';

export function BTPopoverContent({
  align      = 'start',
  side       = 'bottom',
  sideOffset = 8,
  bare       = false,
  className,
  children,
}: BTPopoverContentProps) {
  const ctx        = useBTPopoverContext();
  const contentRef = useRef<HTMLDivElement>(null);

  // ── Positioning ─────────────────────────────────────────────────────────────
  const updatePosition = useCallback(() => {
    const trigger = ctx.triggerRef.current;
    const content = contentRef.current;
    if (!trigger || !content) return;

    // For the default <span> wrapper (display:contents), the first child IS the
    // actual trigger element; for asChild, triggerRef.current IS the element.
    const actualTrigger =
      getComputedStyle(trigger).display === 'contents'
        ? ((trigger.firstElementChild as HTMLElement) ?? trigger)
        : trigger;

    const tRect = actualTrigger.getBoundingClientRect();
    const cRect = content.getBoundingClientRect();

    let top  = 0;
    let left = 0;

    // Main axis
    if      (side === 'bottom') top  = tRect.bottom + sideOffset;
    else if (side === 'top')    top  = tRect.top - cRect.height - sideOffset;
    else if (side === 'right')  left = tRect.right  + sideOffset;
    else /* left */             left = tRect.left  - cRect.width - sideOffset;

    // Cross axis
    if (side === 'top' || side === 'bottom') {
      if      (align === 'start')  left = tRect.left;
      else if (align === 'center') left = tRect.left + tRect.width / 2 - cRect.width / 2;
      else /* end */               left = tRect.right - cRect.width;
    } else {
      if      (align === 'start')  top  = tRect.top;
      else if (align === 'center') top  = tRect.top + tRect.height / 2 - cRect.height / 2;
      else /* end */               top  = tRect.bottom - cRect.height;
    }

    content.style.top  = `${Math.round(top)}px`;
    content.style.left = `${Math.round(left)}px`;

    // Reveal with entrance animation
    content.classList.add('bt-popover-content--visible');
  }, [side, align, sideOffset]);

  // ── Mount / positioning effect ────────────────────────────────────────────
  useEffect(() => {
    if (!ctx.isOpen) return;

    // rAF ensures the portal is painted before we measure its dims.
    const raf = requestAnimationFrame(updatePosition);

    const handleScroll = () => updatePosition();
    const handleResize = () => updatePosition();

    document.addEventListener('scroll', handleScroll, true);
    window.addEventListener  ('resize', handleResize);

    return () => {
      cancelAnimationFrame(raf);
      document.removeEventListener('scroll', handleScroll, true);
      window.removeEventListener  ('resize', handleResize);
    };
  }, [ctx.isOpen, updatePosition]);

  // ── Click-outside + Escape ────────────────────────────────────────────────
  useEffect(() => {
    if (!ctx.isOpen) return;

    function handleDocClick(e: MouseEvent) {
      const trigger = ctx.triggerRef.current;
      const content = contentRef.current;
      if (trigger?.contains(e.target as Node) || content?.contains(e.target as Node)) return;
      ctx.close();
    }

    function handleKeyDown(e: KeyboardEvent) {
      if (e.key === 'Escape') ctx.close();
    }

    document.addEventListener('click',   handleDocClick, true);
    document.addEventListener('keydown', handleKeyDown);

    return () => {
      document.removeEventListener('click',   handleDocClick, true);
      document.removeEventListener('keydown', handleKeyDown);
    };
  }, [ctx.isOpen, ctx]);

  // ── Render ────────────────────────────────────────────────────────────────
  if (!ctx.isOpen) return null;

  return createPortal(
    <div
      ref={contentRef}
      className={['bt-popover-content', bare && 'bt-popover-content--bare', className].filter(Boolean).join(' ')}
      role="dialog"
      tabIndex={-1}
    >
      {children}
    </div>,
    document.body,
  );
}

BTPopoverContent.displayName = 'BTPopoverContent';

/**
 * BTPopoverTrigger — click target for the popover.
 *
 * Default: wraps its children in a layout-transparent <span> (display: contents).
 * With asChild: clones the single child element and injects onClick + ref directly,
 *              so no wrapper element is added to the DOM.
 *
 * @example
 * // Default wrapper
 * <BTPopoverTrigger>
 *   <BTButton label="Open" />
 * </BTPopoverTrigger>
 *
 * @example
 * // asChild — zero extra DOM nodes
 * <BTPopoverTrigger asChild>
 *   <BTButton label="Open" />
 * </BTPopoverTrigger>
 */
import { cloneElement, isValidElement } from 'react';
import { useBTPopoverContext } from './BTPopover';
import type { BTPopoverTriggerProps } from './BTPopover.types';

export function BTPopoverTrigger({ children, asChild = false }: BTPopoverTriggerProps) {
  const ctx = useBTPopoverContext();

  if (asChild && isValidElement(children)) {
    // Merge ref + onClick onto the child element directly.
    const child = children as React.ReactElement<{
      onClick?: (e: React.MouseEvent) => void;
      ref?: React.RefCallback<HTMLElement>;
    }>;
    return cloneElement(child, {
      ref: (el: HTMLElement | null) => { ctx.triggerRef.current = el; },
      onClick: (e: React.MouseEvent) => {
        child.props.onClick?.(e);
        ctx.toggle();
      },
    });
  }

  return (
    <span
      ref={ctx.triggerRef as React.MutableRefObject<HTMLSpanElement | null>}
      className="bt-popover-trigger"
      onClick={ctx.toggle}
    >
      {children}
    </span>
  );
}

BTPopoverTrigger.displayName = 'BTPopoverTrigger';

export { BTPopover, useBTPopoverContext }   from './BTPopover';
export { BTPopoverTrigger }                 from './BTPopoverTrigger';
export { BTPopoverContent }                 from './BTPopoverContent';
export type {
  BTPopoverProps,
  BTPopoverTriggerProps,
  BTPopoverContentProps,
  BTPopoverSide,
  BTPopoverAlign,
} from './BTPopover.types';
